const GRID_SIZE = 30;
const MOVE_SPEED = GRID_SIZE;
const SCREEN_WIDTH = 360;
const WIN_Y = -240;
const START_Y = 250;

// Initialize state
if (!state.playerX) {
  state.playerX = 0;
  state.playerY = START_Y;
  state.score = 0;
  state.highestY = START_Y;
  state.gameOver = false;
}

// Get game over sprite
const gameOverSprite = entities.get('Game Over Text');
if (gameOverSprite) {
  gameOverSprite.visible = state.gameOver;
}

if (!state.gameOver) {
  // Handle input
  if (Input.isKeyPressed('ArrowUp')) {
    state.playerY -= MOVE_SPEED;
  }
  if (Input.isKeyPressed('ArrowDown')) {
    state.playerY += MOVE_SPEED;
  }
  if (Input.isKeyPressed('ArrowLeft')) {
    state.playerX -= MOVE_SPEED;
  }
  if (Input.isKeyPressed('ArrowRight')) {
    state.playerX += MOVE_SPEED;
  }

  // Wrap horizontally
  if (state.playerX > SCREEN_WIDTH / 2) {
    state.playerX = -SCREEN_WIDTH / 2;
  }
  if (state.playerX < -SCREEN_WIDTH / 2) {
    state.playerX = SCREEN_WIDTH / 2;
  }

  // Win condition
  if (state.playerY < WIN_Y) {
    // Player won, reset to start and increment score
    state.playerY = START_Y;
    state.playerX = 0;
    state.score++;
    // Update score display
    const scoreSprite = entities.get('Score Display');
    if (scoreSprite) {
      scoreSprite.userData = state.score;
    }
  }

  // Track highest row reached for scoring
  if (state.playerY < state.highestY) {
    state.highestY = state.playerY;
    state.score++;
    const scoreSprite = entities.get('Score Display');
    if (scoreSprite) {
      scoreSprite.userData = state.score;
    }
  }

  // Collision detection with cars
  const carNames = [];
  entities.list().forEach(name => {
    if (name.startsWith('Car_')) carNames.push(name);
  });

  carNames.forEach(carName => {
    const car = entities.get(carName);
    if (car && checkCollision(state.playerX, state.playerY, 20, 20, car.x, car.y, 40, 15)) {
      state.gameOver = true;
      // Reset player position for next attempt
      state.playerX = 0;
      state.playerY = START_Y;
      state.highestY = START_Y;
      state.score = 0;
      const scoreSprite = entities.get('Score Display');
      if (scoreSprite) {
        scoreSprite.userData = 0;
      }
    }
  });

  // Check if in river (death)
  if (state.playerY > -150 && state.playerY < -80) {
    state.gameOver = true;
    state.playerX = 0;
    state.playerY = START_Y;
    state.highestY = START_Y;
    state.score = 0;
    const scoreSprite = entities.get('Score Display');
    if (scoreSprite) {
      scoreSprite.userData = 0;
    }
  }
}

self.setPosition(state.playerX, state.playerY);

function checkCollision(x1, y1, w1, h1, x2, y2, w2, h2) {
  return x1 < x2 + w2 &&
         x1 + w1 > x2 &&
         y1 < y2 + h2 &&
         y1 + h1 > y2;
}

// Display score
if (!self.userData) {
  self.userData = 0;
}
const score = state.score || 0;
self.userData = score;

const SPEED = 80; // px/s
const ROW_Y = 100;
const SPAWN_X = -400;
const DESPAWN_X = 400;

if (self.x === undefined) {
  self.x = SPAWN_X;
  self.y = ROW_Y;
}

// Move right
self.x += SPEED * dt;

// Respawn at left when off screen
if (self.x > DESPAWN_X) {
  self.x = SPAWN_X;
}

self.setPosition(self.x, self.y);

